{
  "description": "Hive-Mind claude-mem Codex hook integration using global temporal data",
  "hooks": {
    "SessionStart": [
      {
        "matcher": "startup|resume",
        "hooks": [
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh version-check",
            "timeout": 5
          },
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh ensure-worker",
            "timeout": 60
          },
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh hook codex context",
            "timeout": 60,
            "statusMessage": "Loading claude-mem context"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh hook codex session-init",
            "timeout": 60
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "^Bash$|^mcp__.+__(read|view|cat)(_file|_files)?$",
        "hooks": [
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh hook codex file-context",
            "timeout": 30
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": ".*",
        "hooks": [
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh hook codex observation",
            "timeout": 120
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "/home/michel/Documentos/Projects/Hive-Mind/scripts/claude-mem-hook.sh hook codex summarize",
            "timeout": 60
          }
        ]
      }
    ]
  }
}
